function BatteryIcon({
  color,
  percent = 80,
}: {
  color: string;
  percent?: number;
}) {
  const clamped = Math.max(0, Math.min(100, percent));
  // Geometry preserved from Frame 2.svg, but drawn as stroke-only so the
  // status bar background shows through (no grey wash).
  return (
