471	    <div className="relative flex w-[390px] max-w-full items-center justify-center sm:w-[429px]">
472	      <div className="-left-24 -translate-y-1/2 absolute top-1/2 flex items-center gap-2">
473	        <Button
474	          isIconOnly
475	          variant="flat"
476	          radius="full"
477	          aria-label="Previous platform"
478	          onPress={onPrev}
479	          className="min-w-10 h-10 w-10 p-0 text-zinc-500 transition-colors hover:text-zinc-200"
480	        >
