492	        </Button>
493	      </div>
494	      <PlatformCTASwitcher
495	        actionKey={actionKey}
496	        action={action}
497	        iconSrc={iconSrc}
498	        comingSoon={comingSoon}
499	      />
500	    </div>
501	  );
