530	function useFloatingCta(
531	  phoneRef: React.RefObject<HTMLDivElement | null>,
532	): boolean {
533	  const [floating, setFloating] = useState(false);
534	
535	  useEffect(() => {
536	    const phone = phoneRef.current;
537	    if (!phone) return;
538	
539	    const update = (): void => {
540	      const phoneRect = phone.getBoundingClientRect();
541	      const vh = window.innerHeight;
542	      // Threshold is tuned so the floating button and its static-flow slot
543	      // line up vertically at the moment of switch — the visual position
544	      // doesn't jump.
545	      const phoneEnoughVisible = phoneRect.top < vh - 200;
546	      // The floating button sits at vh - 56 (bottom-6 + button height). The
547	      // static slot sits at phoneRect.bottom + 62 (flex gap-8 + pt-2 + half
548	      // button). The switch happens when the two y positions match.
549	      const phoneStillNearBottom = phoneRect.bottom > vh - 118;
550	      setFloating(phoneEnoughVisible && phoneStillNearBottom);
551	    };
552	
553	    update();
554	    window.addEventListener("scroll", update, { passive: true });
555	    window.addEventListener("resize", update);
556	    return () => {
557	      window.removeEventListener("scroll", update);
558	      window.removeEventListener("resize", update);
559	    };
560	  }, [phoneRef]);
561	
562	  return floating;
563	}
