565	const TYPING_DELAY_MS = 450;
566	const TYPING_DURATION_MS = 850;
567	
568	function useStaggeredMessages(
569	  platform: Platform,
570	  enabled: boolean,
571	): ChatMessageItem[] {
572	  const allMessages = platform.demo.messages;
573	  const [visibleCount, setVisibleCount] = useState(1);
574	  const [showTyping, setShowTyping] = useState(false);
575	
576	  useEffect(() => {
577	    setVisibleCount(1);
578	    setShowTyping(false);
579	    if (!enabled) return;
580	    if (allMessages.length <= 1) return;
581	
582	    const timers: ReturnType<typeof setTimeout>[] = [];
583	    let elapsed = 0;
584	    for (let i = 1; i < allMessages.length; i++) {
585	      elapsed += TYPING_DELAY_MS;
586	      timers.push(setTimeout(() => setShowTyping(true), elapsed));
587	      elapsed += TYPING_DURATION_MS;
588	      timers.push(
589	        setTimeout(() => {
590	          setShowTyping(false);
591	          setVisibleCount((c) => c + 1);
592	        }, elapsed),
593	      );
594	    }
595	
596	    return () => {
597	      for (const t of timers) clearTimeout(t);
598	    };
599	  }, [allMessages, enabled]);
600	
601	  return useMemo(() => {
602	    const real = allMessages.slice(0, visibleCount).map((m, i) => ({
603	      ...m,
604	      id: m.id ?? `msg-${i}`,
605	    }));
606	    if (!showTyping || visibleCount >= allMessages.length) return real;
607	    const next = allMessages[visibleCount];
608	    return [
609	      ...real,
610	      {
611	        id: `typing-${visibleCount}`,
612	        from: next.from,
613	        author: next.author,
614	        avatar: next.avatar,
615	        authorColor: next.authorColor,
616	        typing: true,
617	      },
618	    ];
619	  }, [allMessages, visibleCount, showTyping]);
620	}
