"use client";

import { Button } from "@heroui/button";
import { Chip } from "@heroui/chip";
import {
  ArrowLeft02Icon,
  ArrowRight02Icon,
  CircleArrowRight02Icon,
  SquareLockIcon,
} from "@icons";
import { AnimatePresence } from "motion/react";
import * as m from "motion/react-m";
import Image from "next/image";
import type { ReactNode } from "react";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { RaisedButton } from "@/components/ui/raised-button";
import { Link } from "@/i18n/navigation";

import {
  ChatDemo,
  type ChatMessageItem,
  type ChatPlatform,
} from "../iphone/ChatDemo";
import { IPhoneMockup } from "../iphone/IPhoneMockup";
import LargeHeader from "../shared/LargeHeader";

interface ActionLink {
  label: string;
  href: string;
  external?: boolean;
}

interface PhoneConfig {
  screenBackground?: string;
  statusBarTone?: "auto" | "light" | "dark";
}

interface DemoConfig {
  title?: string;
  subtitle?: string;
  messages: ChatMessageItem[];
}

interface Platform {
  id: ChatPlatform;
  name: string;
  icon: string | ReactNode;
  comingSoon?: boolean;
  primaryAction: ActionLink;
  phone: PhoneConfig;
  demo: DemoConfig;
}

const AVATAR_ARYAN = "/aryan-avatar.webp";

function IMessageChipIcon({ size = 20 }: { size?: number }) {
  return (
    // biome-ignore lint/a11y/noSvgWithoutTitle: decorative brand icon, hidden from a11y tree
