      external: true,
    },
    phone: { screenBackground: "#1E1F22", statusBarTone: "light" },
    demo: {
      title: "general",
      messages: [
        {
          author: "Aryan",
          avatar: AVATAR_ARYAN,
          authorColor: "#F47FFF",
